import React, { useState, useRef, useEffect, useMemo } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Dimensions, ScrollView, Image, SafeAreaView, Platform, Animated} from 'react-native';
import { useNavigation, useFocusEffect } from '@react-navigation/native';
import { getHosePrices } from '../components/Prices/HosePrices';
import ScrollableGradientWrapper from '../components/ScrollableGradientWrapper';
import BackButton from '../components/BackButton';

const { width: SCREEN_WIDTH } = Dimensions.get('window');
const isMobile = SCREEN_WIDTH < 700;

const HoseSizeButton = ({ size, insideDiameter, specs, hosePrice, onPress, isSelected }) => {
  const [isHovered, setIsHovered] = useState(false);
  
  return (
    <View style={styles.buttonContainer}>
      <TouchableOpacity 
        style={[
          styles.sizeButton, 
          isSelected && styles.selectedSizeButton,
          isHovered && styles.hoveredSizeButton
        ]} 
        onPress={onPress}
        onMouseEnter={Platform.OS === 'web' ? () => setIsHovered(true) : undefined}
        onMouseLeave={Platform.OS === 'web' ? () => setIsHovered(false) : undefined}
      >
        <View style={styles.sizeContent}>
          <Text style={styles.sizeButtonText}>{size}</Text>
          <Text 
            style={styles.sizeDescription}
            numberOfLines={1}
            ellipsizeMode="tail"
          >
            Inside Diameter: {insideDiameter}
          </Text>
          <View style={styles.hoseImageContainer}>
            <Image
              source={require('../assets/hose_cross_section.png')}
              style={styles.hoseCrossSection}
              resizeMode="contain"
            />
            <Image
              source={require('../assets/hose_image.png')}
              style={styles.hoseImage}
              resizeMode="contain"
            />
          </View>
          <View style={[styles.priceBorder, isSelected && styles.selectedPriceBorder]}>
            <Text style={[styles.priceText, isSelected && styles.selectedPriceText]}>A${hosePrice}</Text>
          </View>
        </View>
      </TouchableOpacity>
      <View style={styles.specsContainer}>
        {specs.map((spec, index) => (
          <Text 
            key={index}
            style={styles.specText}
            numberOfLines={1}
            ellipsizeMode="tail"
          >
            • {spec}
          </Text>
        ))}
      </View>
    </View>
  );
};

const HoseSelectionScreen = ({ route }) => {
  const navigation = useNavigation();
  const [selectedSize, setSelectedSize] = useState(null);
  const [selectedHosePrice, setSelectedHosePrice] = useState(null);
  const contentFadeAnim = useRef(new Animated.Value(0)).current;
  const { isHoseOnly } = route.params || { isHoseOnly: false };
  
  // Get prices directly - no async needed
  const prices = getHosePrices();

  const hoseSizes = useMemo(() => [
    { 
      size: '1/4"', 
      insideDiameter: '1/4 Inch',
      hosePrice: `  ${prices["1/4"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 6525psi',
        'Burst Pressure: 26,100psi',
        'Bend Radius: 50mm'
      ]
    },
    { 
      size: '3/8"', 
      insideDiameter: '3/8 Inch',
      hosePrice: `  ${prices["3/8"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 5438psi',
        'Burst Pressure: 21,752psi',
        'Bend Radius: 75mm'
      ]
    },
    { 
      size: '1/2"', 
      insideDiameter: '1/2 Inch',
      hosePrice: `  ${prices["1/2"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 4495psi',
        'Burst Pressure: 17,980psi',
        'Bend Radius: 100mm'
      ]
    },
    { 
      size: '5/8"', 
      insideDiameter: '5/8 Inch',
      hosePrice: `  ${prices["5/8"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 4350psi',
        'Burst Pressure: 17,400psi',
        'Bend Radius: 130mm'
      ]
    },
    { 
      size: '3/4"', 
      insideDiameter: '3/4 Inch',
      hosePrice: `  ${prices["3/4"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 4162psi',
        'Burst Pressure: 16,675psi',
        'Bend Radius: 200mm'
      ]
    },
    { 
      size: '1"', 
      insideDiameter: '1 Inch',
      hosePrice: `  ${prices["1"]}/meter`,
      specs: [
        'Two Wire Steel Braided EN 857 2SC',
        'Working Pressure: 3263psi',
        'Burst Pressure: 13,050psi',
        'Bend Radius: 250mm'
      ]
    },
  ], [prices]);

  const handleSizeSelection = (size, hosePrice) => {
    setSelectedSize(size);
    const cleanPrice = hosePrice.trim().split('/')[0].trim();
    setSelectedHosePrice(cleanPrice);
  
    // Fade out animation
    Animated.timing(contentFadeAnim, {
      toValue: 0,
      duration: 600,
      useNativeDriver: Platform.OS !== 'web',
    }).start(() => {
      if (isHoseOnly) {
        navigation.navigate('CutLengths', {
          selectedHose: { size: size },
          selectedHosePrice: cleanPrice,
          isHoseOnly: true
        });
      } else {
        navigation.navigate('End1Fitting', {
          selectedHose: { size: size },
          selectedHosePrice: cleanPrice
        });
      }
    });
  };

  // Fade in on mount
  useEffect(() => {
    Animated.timing(contentFadeAnim, {
      toValue: 1,
      duration: 600,
      useNativeDriver: Platform.OS !== 'web',
    }).start();
  }, []);

  // Reset fade-in when screen comes into focus
  useFocusEffect(
    React.useCallback(() => {
      contentFadeAnim.setValue(0);
      Animated.timing(contentFadeAnim, {
        toValue: 1,
        duration: 600,
        useNativeDriver: Platform.OS !== 'web',
      }).start();
    }, [contentFadeAnim])
  );

  return (
    <Animated.View style={[styles.mainContainer, { opacity: contentFadeAnim }]}>
      <BackButton onPress={() => navigation.goBack()} />
      
      <ScrollableGradientWrapper>
        <SafeAreaView style={styles.container}>
          <View style={styles.logoContainer}>
            <Image
              source={require('../assets/fluidpower_logo.gif')}
              style={styles.logo}
              resizeMode="contain"
            />
          </View>
          
          <Animated.View style={[styles.contentContainer, { opacity: contentFadeAnim }]}>
            <ScrollView 
              style={styles.mainScrollView}
              contentContainerStyle={styles.mainScrollViewContent}
              showsVerticalScrollIndicator={true}
            >
              <View style={styles.titleContainer}>
                <Text style={styles.title}>Select Hose Size</Text>
              </View>
              <View style={styles.scrollViewContent}>
                {hoseSizes.map((hose, index) => (
                  <HoseSizeButton
                    key={index}
                    size={hose.size}
                    insideDiameter={hose.insideDiameter}
                    specs={hose.specs}
                    hosePrice={hose.hosePrice}
                    onPress={() => handleSizeSelection(hose.size, hose.hosePrice)}
                    isSelected={selectedSize === hose.size}
                  />
                ))}
              </View>
            </ScrollView>
          </Animated.View>
        </SafeAreaView>
      </ScrollableGradientWrapper>
    </Animated.View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
  },
  mainContainer: {
    flex: 1,
    position: 'relative',
  },
  mainScrollView: {
    flex: 1,
  },
  mainScrollViewContent: {
    flexGrow: 1,
    paddingBottom: 20,
  },
  contentContainer: {
    flex: 1,
  },
  logoContainer: {
    alignItems: 'center',
    justifyContent: 'center',
    marginVertical: 20,
    width: '100%',
  },
  logo: {
    width: 400,
    height: 200,
    resizeMode: 'contain',
  },
  titleContainer: {
    alignSelf: 'center',
    marginBottom: 30,
    marginTop: 10,
    backgroundColor: '#4a4a4a',
    borderRadius: 25,
    paddingVertical: 12,
    paddingHorizontal: 25,
  },
  scrollViewContent: {
    alignItems: 'center',
    paddingHorizontal: 15,
    paddingBottom: 20,
  },
  title: {
    fontSize: 24,
    fontWeight: 'bold',
    color: 'white',
  },
  buttonContainer: {
    flexDirection: 'row',
    justifyContent: 'center',
    alignItems: 'flex-start',
    marginBottom: 10,
    width: '100%',
    maxWidth: 600,
    paddingHorizontal: 0,
  },
  sizeButton: {
    width: isMobile ? 160 : 220,
    height: isMobile ? 150 : 160,
    borderWidth: 4,
    borderColor: '#4a4a4a',
    borderRadius: 30,
    overflow: 'hidden',
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: 'transparent',
    paddingBottom: 10,
    marginBottom: 15,
    marginRight: isMobile ? 2 : 30,
    shadowColor: '#000',
    shadowOffset: { width: 5, height: 8 },
    shadowOpacity: 0.25,
    shadowRadius: 3.84,
    elevation: 5,
    transition: 'all 0.2s ease',
  },
  selectedSizeButton: {
    backgroundColor: '#ffc100',
  },
  hoveredSizeButton: {
    transform: [{ scale: 1.02 }],
    shadowOffset: { width: 6, height: 10 },
    shadowOpacity: 0.3,
    shadowRadius: 5,
    elevation: 8,
  },
  sizeContent: {
    alignItems: 'center',
    width: '100%',
    paddingHorizontal: 0,
  },
  sizeButtonText: {
    fontSize: isMobile ? 20 : 24,
    fontWeight: 'bold',
    color: '#333',
    marginBottom: isMobile ? 0 : 5,
  },
  sizeDescription: {
    fontSize: isMobile ? 12 : 14,
    color: '#666',
    marginBottom: 5,
    textAlign: 'center',
    width: '100%',
    ...(Platform.OS === 'web' && { whiteSpace: 'nowrap' }),
  },
  hoseImageContainer: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    ...(isMobile && { transform: [{ scale: 0.9 }] })
  },
  hoseCrossSection: {
    width: isMobile ? 35 : 40,
    height: isMobile ? 35 : 40,
    marginRight: 6,
  },
  hoseImage: {
    width: isMobile ? 70 : 80,
    height: isMobile ? 35 : 40,
  },
  priceBorder: {
    borderWidth: 2,
    borderColor: '#4a4a4a',
    borderRadius: 15,
    padding: isMobile ? 3 : 5,
    marginTop: isMobile ? 3 : 5,
    backgroundColor: '#ffc100',
  },
  selectedPriceBorder: {
    backgroundColor: 'transparent',
  },
  priceText: {
    fontSize: isMobile ? 14 : 16,
    fontWeight: 'bold',
    color: '#4a4a4a',
  },
  selectedPriceText: {
    color: '#333',
  },
  specsContainer: {
    width: isMobile ? 220 : 250,
    marginLeft: 10,
  },
  specText: {
    fontSize: isMobile ? 12 : 14,
    color: '#666',
    marginBottom: 3,
  },
});

export default HoseSelectionScreen;